            self.emit_line("// -1 * -1 = 1");
            self.emit_line("4'b0000: ternary_mul_lut = TRIT_POS_1;");
            self.emit_line("// -1 * 0 = 0");
            self.emit_line("4'b0010: ternary_mul_lut = TRIT_ZERO;");
            self.emit_line("// -1 * 1 = -1");
            self.emit_line("4'b0100: ternary_mul_lut = TRIT_NEG_1;");
            self.emit_line("// 0 * -1 = 0");
            self.emit_line("4'b0110: ternary_mul_lut = TRIT_ZERO;");
            self.emit_line("// 0 * 0 = 0");
            self.emit_line("4'b1000: ternary_mul_lut = TRIT_ZERO;");
            self.emit_line("// 0 * 1 = 0");
            self.emit_line("4'b1010: ternary_mul_lut = TRIT_ZERO;");
            self.emit_line("// 1 * -1 = -1");
            self.emit_line("4'b1100: ternary_mul_lut = TRIT_NEG_1;");
            self.emit_line("// 1 * 0 = 0");
            self.emit_line("4'b1110: ternary_mul_lut = TRIT_ZERO;");
            self.emit_line("// 1 * 1 = 1");
            self.emit_line("4'b0001: ternary_mul_lut = TRIT_POS_1;");
            self.dedent();
            self.emit_line("endcase");
            self.emit_line("endfunction");
            self.emit_line("");
            self.emit_line("// Accumulator for partial products");
            self.emit_line("reg [31:0] accumulator;");
            self.emit_line("reg [7:0] unit_idx;");
            self.emit_line("");
            self.emit_line("initial begin");
            self.indent();
            self.emit_line("accumulator <= 32'd0;");
            self.emit_line("unit_idx <= 8'd0;");
            self.dedent();
            self.emit_line("end");
            self.emit_line("");
            self.emit_line("// MAC operation");
            self.emit_line("always @(posedge clk) begin");
            self.indent();
            self.emit_line("if (!rst_n) begin");
            self.indent();
            self.emit_line("accumulator <= 32'd0;");
            self.emit_line("unit_idx <= 8'd0;");
            self.emit_line("valid <= 1'b0;");
            self.dedent();
            self.emit_line("end else if (enable) begin");
            self.indent();
            self.emit_line("// Process 8 parallel units over 8 cycles");
            self.emit_line("case (unit_idx)");
            self.indent();
            self.emit_line("8'd0: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd1: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd2: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd3: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd4: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd5: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd6: unit_idx <= unit_idx + 1'b1;");
            self.emit_line("8'd7: begin");
            self.indent();
            self.emit_line("valid <= 1'b1;");
            self.emit_line("unit_idx <= 8'd0;");
            self.dedent();
            self.emit_line("endcase");
            self.dedent();
            self.emit_line("end");
            self.dedent();
            self.emit_line("end");
            self.emit_line("");
            self.emit_line("// Accumulator output");
            self.emit_line("assign acc_out = accumulator;");
            self.emit_line("");
            self.emit_line("endmodule");
            self.emit_line("");
        end
    endtask

    // function: emit
    task emit;
        input [31:0] self;
        input [31:0] s;
        begin
            self.output.append(s);
        end
    endtask

    // function: emit_line
    task emit_line;
        input [31:0] self;
        input [31:0] s;
        begin
            self.output.append(s);
            self.output.append("
");
        end
    endtask

    // function: emit_int
    task emit_int;
        input [31:0] self;
        input [31:0] n;
        begin
            self.emit(int_to_str(n));
        end
    endtask

    // function: indent
    task indent;
        input [31:0] self;
        // TODO: implement
    endtask

    // function: dedent
    task dedent;
        input [31:0] self;
        begin
