            end
        end
    endtask

    // function: int_to_str
    function [31:0] int_to_str; // -> []const u8
        input [31:0] n;
        begin
            if ((n == 0)) begin
                int_to_str = "0";
            end
            reg [31:0] buf = /* array [0;5]{} */;
            reg [31:0] len = 0;
            while ((n > 0)) begin
                reg [31:0] digit = (n % 10);
                len = (len + 1);
                val = (n / 10);
            end
            while ((i < (len / 2))) begin
                reg [31:0] tmp = buf[i];
                buf[i] = buf[((len - 1) - i)];
                buf[((len - 1) - i)] = tmp;
